      {
        "title": "Proper Grip",
        "content": "Hold the guitar neck with your left hand. \n- Use your thumb to support the back. \n- Keep your fingers curved."
      },
      {
        "title": "Finger Placement",
        "content": "Place your fingers just behind the frets. \n- Use the tips of your fingers. \n- Avoid touching adjacent strings."
      },
      {
        "title": "Relaxation Techniques",
        "content": "Keep your hands relaxed. \n- Shake out tension before playing. \n- Take breaks to avoid strain."
      }
    ]
  }
}
